  1→import React, { useState, useRef, useCallback } from 'react';
  2→import { Sparkles, TrendingUp, Target, Award, MousePointerClick, ArrowRight, ScanLine, Code2, Globe2, Fuel, Zap, Star, Check, Search, Bot, BrainCircuit, Database, Share2, Layers, Infinity, Radio, Globe, Droplet, Loader2, Gift, Shield, UserCheck, GraduationCap, BadgeCheck } from 'lucide-react';
  3→import { User } from '../types';
  4→import ScoreRing from '../components/ScoreRing';
  5→import { auditAnswerFirst, AnswerFirstAuditResult } from '../services/answer-first-audit';
  6→
  7→interface HomeProps {
  8→  onNavigate: (view: 'analyze' | 'login' | 'recharge' | 'directory') => void;
  9→  user: User | null;
 10→  onDirectRecharge?: (packId: number) => void;
 11→}
 12→
 13→const Home: React.FC<HomeProps> = ({ onNavigate, user, onDirectRecharge }) => {
 14→
 15→  // ── Score Gratuit State ──
 16→  const [brandName, setBrandName] = useState('');
 17→  const [siteUrl, setSiteUrl] = useState('');
 18→  const [isAnalyzing, setIsAnalyzing] = useState(false);
 19→  const [auditResult, setAuditResult] = useState<AnswerFirstAuditResult | null>(null);
 20→  const [auditError, setAuditError] = useState<string | null>(null);
 21→  const resultsRef = useRef<HTMLDivElement>(null);
 22→
 23→  // ── Free Audit Gating ──
 24→  const [freeAuditUsed, setFreeAuditUsed] = useState(() => {
 25→    return localStorage.getItem('citedby_free_audit_used') === 'true';
 26→  });
 27→
 28→  // Derive E-E-A-T pillar scores from the 6 audit categories
 29→  const eeatPillars = auditResult ? [
 30→    { label: 'Experience', icon: <UserCheck size={16} />, score: Math.round((auditResult.categories.contentFreshness.score + auditResult.categories.answerFirst.score) / 2) },
 31→    { label: 'Expertise', icon: <GraduationCap size={16} />, score: Math.round((auditResult.categories.faqStructure.score + auditResult.categories.semanticHtml.score) / 2) },
 32→    { label: 'Authority', icon: <BadgeCheck size={16} />, score: Math.round((auditResult.categories.schemaOrg.score + auditResult.categories.metaOptimization.score) / 2) },
 33→    { label: 'Trust', icon: <Shield size={16} />, score: Math.round((auditResult.categories.metaOptimization.score + auditResult.categories.schemaOrg.score + auditResult.categories.answerFirst.score) / 3) },
 34→  ] : [];
 35→
 36→  const handleFreeAudit = useCallback(async () => {
 37→    // If free audit already used, redirect to signup
 38→    if (freeAuditUsed) {
 39→      onNavigate('login');
 40→      return;
 41→    }
 42→
 43→    if (!brandName.trim() || !siteUrl.trim()) {
 44→      setAuditError('Veuillez remplir les deux champs.');
 45→      return;
 46→    }
 47→    // Basic URL validation
 48→    let finalUrl = siteUrl.trim();
 49→    if (!/^https?:\/\//i.test(finalUrl)) {
 50→      finalUrl = 'https://' + finalUrl;
 51→    }
 52→    try {
 53→      new URL(finalUrl);
 54→    } catch {
 55→      setAuditError('URL invalide. Exemple : https://www.example.com');
 56→      return;
 57→    }
 58→
 59→    setAuditError(null);
 60→    setAuditResult(null);
 61→    setIsAnalyzing(true);
 62→
 63→    try {
 64→      const result = await auditAnswerFirst(finalUrl, brandName.trim());
 65→      setAuditResult(result);
 66→      // Mark free audit as used
 67→      localStorage.setItem('citedby_free_audit_used', 'true');
 68→      setFreeAuditUsed(true);
 69→      // Scroll to results after a small delay for render
 70→      setTimeout(() => {
 71→        resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
 72→      }, 150);
 73→    } catch (err) {
 74→      setAuditError('Une erreur est survenue lors de l\'analyse. Veuillez reessayer.');
 75→    } finally {
 76→      setIsAnalyzing(false);
 77→    }
 78→  }, [brandName, siteUrl, freeAuditUsed, onNavigate]);
 79→
 80→  const getScoreLabel = (score: number): string => {
 81→    if (score >= 80) return 'Excellent';
 82→    if (score >= 60) return 'Bon';
 83→    if (score >= 40) return 'Moyen';
 84→    if (score >= 20) return 'Faible';
 85→    return 'Critique';
 86→  };
 87→
 88→  const getScoreColor = (score: number): string => {
 89→    if (score >= 80) return 'text-purple-400';
 90→    if (score >= 60) return 'text-violet-400';
 91→    if (score >= 40) return 'text-amber-400';
 92→    return 'text-red-400';
 93→  };
 94→
 95→  const getBarColor = (score: number): string => {
 96→    if (score >= 80) return 'bg-purple-500';
 97→    if (score >= 60) return 'bg-violet-500';
 98→    if (score >= 40) return 'bg-amber-500';
 99→    return 'bg-red-500';
100→  };
101→
102→  const handleStartAnalysis = () => {
103→    if (user) {
104→      onNavigate('analyze');
105→    } else {
106→      onNavigate('login');
107→    }
108→  };
109→
110→  const handleSelectPlan = (packId: number) => {
111→    if (user) {
112→      if (onDirectRecharge) {
113→        onDirectRecharge(packId);
114→      } else {
115→        onNavigate('recharge');
116→      }
117→    } else {
118→      onNavigate('login');
119→    }
120→  };
121→
122→  const plans = [
123→    {
124→      id: 1,
125→      name: "Le Jerrican",
126→      credits: 50,
127→      price: 15,
128→      icon: <Droplet size={24} />,
129→      popular: false,
130→      features: ["Id\u00e9al pour tester", "1 Audit complet", "Valable 1 an"]
131→    },
132→    {
133→      id: 2,
134→      name: "La Pompe",
135→      credits: 200,
136→      price: 49,
137→      icon: <Fuel size={24} />,
138→      popular: true,
139→      features: ["Pour optimiser s\u00e9rieusement", "Support prioritaire", "+10% Bonus offert"]
140→    },
141→    {
142→      id: 3,
143→      name: "La Citerne",
144→      credits: 1000,
145→      price: 199,
146→      icon: <Database size={24} />,
147→      popular: false,
148→      features: ["Usage intensif / Agence", "Acc\u00e8s API Beta", "+20% Bonus offert"]
149→    }
150→  ];
151→
152→  return (
153→    <div className="w-full max-w-[1440px] mx-auto px-6 pt-16 pb-32 page-enter">
