155→      {/* ── HERO SECTION ── */}
156→      <div className="text-center mb-32 relative">
157→        {/* Ambient glow */}
158→        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[700px] h-[500px] bg-purple-600/8 blur-[150px] rounded-full -z-10 pointer-events-none"></div>
159→
160→        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.03] border border-white/[0.06] text-gray-400 text-xs font-medium tracking-wide uppercase mb-10">
161→          <Sparkles size={12} className="text-purple-400" />
162→          <span>Plateforme AEO / GEO</span>
163→        </div>
164→
165→        <h1 className="text-5xl sm:text-6xl md:text-[5.5rem] font-sans font-bold tracking-tight text-white leading-[1.05] mb-8">
166→          Analysez & Optimisez<br />
167→          votre pr{'\u00e9'}sence dans les<br />
168→          <span className="text-purple-400">r{'\u00e9'}sultats de recherche IA</span>
169→        </h1>
170→
171→        <p className="text-lg md:text-xl text-gray-500 max-w-2xl mx-auto leading-relaxed mb-12 font-light">
172→          La premi{'\u00e8'}re plateforme d'Answer Engine Optimization. Mesurez, corrigez et boostez votre visibilit{'\u00e9'} dans les r{'\u00e9'}ponses de ChatGPT, Perplexity, Gemini, Claude, Copilot et AI Overviews.
173→        </p>
174→
175→        <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
176→          <button onClick={handleStartAnalysis} className="btn-gradient text-base px-8 py-3.5 flex items-center gap-2.5 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30">
177→            Lancer un Audit Gratuit <ArrowRight size={18} />
178→          </button>
179→          <button onClick={() => onNavigate('directory')} className="px-8 py-3.5 rounded-full border border-white/[0.06] text-gray-300 text-base font-medium hover:bg-white/[0.03] hover:border-white/[0.15] transition-all">
180→            Explorer l'Annuaire
181→          </button>
182→        </div>
183→      </div>
184→
185→      {/* ── SECTION AEO / GEO ── */}
186→      <div className="mt-20 md:mt-28 max-w-5xl mx-auto px-6 mb-32">
187→        <h2 className="text-center text-2xl md:text-3xl font-semibold tracking-tight">
188→          <span className="text-white">Qu'est-ce que l'</span>
189→          <span className="text-purple-400">AEO</span>
190→          <span className="text-white"> / </span>
